// Email veya ad yoksa satırı atla (form henüz doldurulmamış olabilir)
const name = ($input.item.json['Adın Soyadın'] || '').trim();
const email = ($input.item.json['E-Posta Adresin'] || '').trim();
if (!name || !email) {
  return [];
}

const rawDate = $input.item.json["Doğum Tarihin (GG/AA/YYYY)"];

const aylar = {
  "ocak": 0, "subat": 1, "şubat": 1, "mart": 2, "nisan": 3,
  "mayis": 4, "mayıs": 4, "haziran": 5, "temmuz": 6,
  "agustos": 7, "ağustos": 7, "eylul": 8, "eylül": 8,
  "ekim": 9, "kasim": 10, "kasım": 10, "aralik": 11, "aralık": 11
};

const nullResult = {
  json: {
    ...$input.item.json,
    age: null,
    birthDateParsed: null
  }
};

if (!rawDate || rawDate.toString().trim() === "") {
  return nullResult;
}

let day, month, year;
const str = rawDate.toString().trim();

if (str.includes("/") || str.includes(".") || str.includes("-")) {
  const parts = str.split(/[\/\.\-]/);
  day   = parseInt(parts[0], 10);
  month = parseInt(parts[1], 10) - 1;
  year  = parseInt(parts[2], 10);

} else if (/^\d{8}$/.test(str)) {
  day   = parseInt(str.substring(0, 2), 10);
  month = parseInt(str.substring(2, 4), 10) - 1;
  year  = parseInt(str.substring(4, 8), 10);

} else {
  const parts = str.toLowerCase().split(" ").filter(p => p !== "");

  if (parts.length !== 3) {
    return nullResult;
  }

  day  = parseInt(parts[0], 10);
  year = parseInt(parts[2], 10);

  if (!isNaN(parseInt(parts[1], 10))) {
    month = parseInt(parts[1], 10) - 1;
  } else {
    month = aylar[parts[1]];
    if (month === undefined) {
      return nullResult;
    }
  }
}

if (isNaN(day) || isNaN(month) || isNaN(year)) {
  return nullResult;
}

const birthDate = new Date(year, month, day);
const today = new Date();

let age = today.getFullYear() - birthDate.getFullYear();
const monthDiff = today.getMonth() - birthDate.getMonth();
const dayDiff   = today.getDate()  - birthDate.getDate();

if (monthDiff < 0 || (monthDiff === 0 && dayDiff < 0)) {
  age--;
}

return {
  json: {
    ...$input.item.json,
    age,
    birthDateParsed: `${day}/${month + 1}/${year}`
  }
};

// Kesin Ret (Topluluk İlkeleri) — Supabase formatı
const d = $input.item.json;

return {
  json: {
    full_name: d['Adın Soyadın'] || '',
    email: (d['E-Posta Adresin'] || '').toLowerCase().trim(),
    birth_date: d['Doğum Tarihin (GG/AA/YYYY)'] || '',
    gender: d['Cinsiyetin'] || '',
    phone: d['Telefon Numaran'] || '',
    status: 'kesin_ret',
    reviewer: 'Otomasyon',
    review_note: 'Topluluk ilkeleri kabul edilmemiş.',
    mail_template: 'kesin-ret-topluluk',

  }
};

